                    var requestMessage = new HttpRequestMessage(HttpMethod.Post, url);
                    requestMessage.Content = new StringContent(context.Request.Body.ToString(), Encoding.UTF8, "application/json");

                    var responseMessage = await httpClient.SendAsync(requestMessage);
                    if (responseMessage.IsSuccessStatusCode) {
                        await context.Response.WriteAsync(responseMessage.Content.ReadAsStringAsync().Result);
                    } else {
                        await context.Response.WriteAsync("An error occurred while forwarding the request.");
                    }
                });
